// Prepend to tuple
type Prepend<T, Tuple extends unknown[]> = [T, ...Tuple];
type WithId<T extends unknown[]> = Prepend<number, T>;

type UserArgs = WithId<[string, string]>;
// [number, string, string]

function createWithId<T extends unknown[]>(
  ...args: WithId<T>
): { id: number; args: T } {
  const [id, ...rest] = args;
  return { id: id as number, args: rest as unknown as T };
}

